#!/usr/bin/env python
from __future__ import print_function
import sys
import os
import subprocess
import datetime

SUPPORTED = {
    'tar.gz':  ('tar', '.tar.gz', lambda out, src: ['tar', '-czf', out, '-C', os.path.dirname(src), os.path.basename(src)]),
    'tgz':     ('tar', '.tgz',    lambda out, src: ['tar', '-czf', out, '-C', os.path.dirname(src), os.path.basename(src)]),
    'tar.bz2': ('tar', '.tar.bz2',lambda out, src: ['tar', '-cjf', out, '-C', os.path.dirname(src), os.path.basename(src)]),
    'tbz':     ('tar', '.tbz',    lambda out, src: ['tar', '-cjf', out, '-C', os.path.dirname(src), os.path.basename(src)]),
    'zip':     ('zip', '.zip',    lambda out, src: ['zip', '-r', out, os.path.basename(src)], True),
    '7z':      ('7z',  '.7z',     lambda out, src: ['7z', 'a', out, os.path.basename(src)]),
}

def which(cmd):
    paths = os.environ.get('PATH', '').split(os.pathsep)
    ext = os.environ.get('PATHEXT', '').split(os.pathsep) if os.name == 'nt' else ['']
    for p in paths:
        for e in ext:
            candidate = os.path.join(p, cmd + e)
            if os.path.isfile(candidate) and os.access(candidate, os.X_OK):
                return candidate
    return None

def usage():
    print("Usage: {} <directory> <format> [output_path]".format(sys.argv[0]), file=sys.stderr)
    print("Supported formats: {}".format(', '.join(sorted(set(SUPPORTED.keys())))), file=sys.stderr)
    sys.exit(1)

def main():
    if len(sys.argv) < 3:
        usage()

    src_dir = os.path.abspath(sys.argv[1])
    fmt_key = sys.argv[2].lower()

    if not os.path.isdir(src_dir):
        print("Error: '{}' is not a directory.".format(src_dir), file=sys.stderr)
        sys.exit(1)

    if fmt_key not in SUPPORTED:
        print("Error: unsupported format '{}'.".format(fmt_key), file=sys.stderr)
        usage()

    cmd_name, ext, builder = SUPPORTED[fmt_key][:3]
    needs_cwd = len(SUPPORTED[fmt_key]) == 4  # zip requires running inside parent to avoid full paths

    if not which(cmd_name):
        print("Error: required command '{}' not found in PATH.".format(cmd_name), file=sys.stderr)
        sys.exit(1)

    timestamp = datetime.datetime.now().strftime('%Y%m%d_%H%M%S')
    default_name = "{}_{}{}".format(os.path.basename(src_dir.rstrip(os.sep)), timestamp, ext)
    output_path = os.path.abspath(sys.argv[3]) if len(sys.argv) >= 4 else os.path.join(os.getcwd(), default_name)

    # Ensure parent directory for output exists
    out_dir = os.path.dirname(output_path)
    if out_dir and not os.path.isdir(out_dir):
        try:
            os.makedirs(out_dir)
        except Exception as e:
            print("Error creating output directory: {}".format(e), file=sys.stderr)
            sys.exit(1)

    cmd = builder(output_path, src_dir)
    cwd = os.path.dirname(src_dir) if needs_cwd else None

    try:
        subprocess.check_call(cmd, cwd=cwd)
        print("Created archive '{}' successfully.".format(output_path))
    except subprocess.CalledProcessError as e:
        print("Backup command failed with exit code {}.".format(e.returncode), file=sys.stderr)
        sys.exit(e.returncode)
    except OSError as e:
        print("Execution failed: {}".format(e), file=sys.stderr)
        sys.exit(1)

if __name__ == '__main__':
    main()